"""
MKT Christ Commentary — Isaiah chapter 42
Run: python3 scripts/zc-christ-isaiah-42.py

Isaiah 42 contains the First Servant Song (vv.1-4) and develops its
implications through the chapter: the Servant's commission (vv.5-9),
the new-song response (vv.10-13), the divine warrior breaking his silence (vv.14-17),
and the paradox of the blind servant (vv.18-25).

Note: verse 1 already exists in output — merge_comm skips it safely.

Key Christological texts:
- 42:1: Already present (Matt 12:18-21 citation — baptism + ministry portrait)
- 42:2-3: Matt 12:19-20 (no street-crying, bruised reed, smoldering wick)
- 42:4: Heb 12:2 (endured the cross for the joy set before him)
- 42:6: "covenant for the people, light for the nations" → Heb 8:6; Acts 13:47
- 42:7: Luke 4:18; John 9 (opening blind eyes, freeing captives)
- 42:8: divine glory → John 17:5 (glory shared with the pre-existent Son)
- 42:10: Rev 5:9 (the new song before the Lamb)
- 42:14: Heb 1:1-2 (long silence broken in the Son)
- 42:21: Matt 5:17 (law magnified and made glorious by Christ)
"""

import json, pathlib

ROOT = pathlib.Path(__file__).parent.parent

def load_comm(source, book):
    p = ROOT / 'data' / 'commentary' / source / f'{book}.json'
    if p.exists():
        return json.loads(p.read_text())
    return {}

def save_comm(source, book, data):
    p = ROOT / 'data' / 'commentary' / source / f'{book}.json'
    p.parent.mkdir(parents=True, exist_ok=True)
    p.write_text(json.dumps(data, ensure_ascii=False, indent=None))
    print(f'  wrote {p.relative_to(ROOT)}')

def merge_comm(existing, new_data):
    """Merge new_data into existing without overwriting present entries."""
    for ch, verses in new_data.items():
        if ch not in existing:
            existing[ch] = {}
        for v, html in verses.items():
            if v not in existing[ch]:
                existing[ch][v] = html

ISAIAH = {
  "42": {
    "2": '<p>"He will not cry aloud or lift up his voice, or make it heard in the street." Matt 12:19 quotes this verse directly as fulfilled in Jesus\'s withdrawal from controversy and his command to silence after healings (12:16: "he ordered them not to make him known"). Mark\'s Gospel is saturated with the "Messianic secret" motif — the repeated commands to silence (1:25,44; 3:12; 5:43; 7:36; 8:30). John 5:41: "I do not receive glory from people." The Servant\'s non-publicity is the opposite of the power-display expected of a messiah — his silence is the silence of the one who "did not count equality with God a thing to be grasped" (Phil 2:6).</p>',
    "3": '<p>"A bruised reed he will not break, and a faintly burning wick he will not quench." Matt 12:20 quotes this. The gentleness of the Servant toward the vulnerable is Christ\'s pastoral signature: the tax collectors and sinners welcomed at table (Luke 15:1-2), the woman caught in adultery (John 8:10-11: "neither do I condemn you"), the prodigal received by the running father (Luke 15:20), the disciples restored after failure (John 21:15-17). The "bruised reed" is the one who has been damaged by life; the "smoldering wick" is the one whose faith is nearly extinguished. Christ tends both rather than discarding them. Matt 12:20 continues: "until he brings justice to victory" — the gentleness serves the ultimate triumph.</p>',
    "4": '<p>"He will not grow faint or be discouraged till he has established justice in the earth; and the coastlands wait for his instruction (<em>tôrâ</em>)." The Servant\'s perseverance "till" — the completion of the mission is guaranteed. Heb 12:2: "who for the joy that was set before him endured the cross, despising the shame, and is seated at the right hand of the throne of God." The coastlands waiting for his Torah (<em>tôrâtô yĕyaḥēlû</em>) is the Gentile mission: Acts 13:47 (Paul and Barnabas quoting 49:6 but fulfilling 42:4\'s expectation); Matt 28:20: "teaching them to observe all that I have commanded you." The law that goes forth from Zion (2:3) is Christ\'s teaching that the Gentile coastlands now receive.</p>',
    "5": '<p>"Thus says God, YHWH, who created the heavens and stretched them out, who spread out the earth and what comes from it, who gives breath to the people on it and spirit to those who walk in it." The creation formula that introduces the Servant\'s commission establishes the commissioner\'s credentials. John 1:3: "all things were made through him, and without him was not anything made that was made." Col 1:16: "by him all things were created, in heaven and on earth." The creator-God who commissions the Servant is the Father who sends the Son — and the Son is himself the one through whom the commission\'s creator-God made the heavens. The creation-authority of the commissioning deity is shared by the one commissioned.</p>',
    "6": '<p>"I am YHWH; I have called you in righteousness; I will take you by the hand and keep you; I will give you as a covenant for the people, a light for the nations." Two of the most significant Servant titles. (1) <em>Bĕrît ʿām</em> (covenant for the people): Heb 8:6: "he is the mediator of a better covenant"; Heb 9:15: "he is the mediator of a new covenant." Christ\'s blood is "the blood of the covenant" (Matt 26:28; Heb 13:20). (2) <em>ʾÔr gôyîm</em> (light for the nations): John 8:12: "I am the light of the world"; Luke 2:32 (Simeon): "a light for revelation to the Gentiles"; Acts 13:47 (Paul and Barnabas): "I have made you a light for the Gentiles." The divine hand-holding and keeping is the "I am with you always" of the Great Commission (Matt 28:20).</p>',
    "7": '<p>"To open the eyes that are blind, to bring out the prisoners from the dungeon, from the prison those who sit in darkness." Luke 4:18 quotes Isaiah 61:1 but fulfills 42:7 also: "to proclaim liberty to the captives and recovering of sight to the blind." John 9 is the enacted fulfillment: the man born blind receives sight, and the chapter explores the deeper blindness of those who claim to see (9:39-41). Acts 26:18: Paul\'s commission from the risen Christ is "to open their eyes, so that they may turn from darkness to light and from the power of Satan to God." Rev 3:17-18: the church at Laodicea is "blind" and needs eye salve from Christ — the prison-opening and eye-opening continue as the Servant\'s ongoing work through the Spirit.</p>',
    "8": '<p>"I am YHWH; that is my name; my glory I give to no other, nor my praise to carved idols." The exclusive divine glory — and yet Christ shares it. John 17:5: "Father, glorify me in your own presence with the glory that I had with you before the world existed." Phil 2:9-11: "God has highly exalted him and bestowed on him the name that is above every name." The glory YHWH refuses to give to any other (v.8) is the glory the pre-existent Son possessed before the incarnation and received fully at the resurrection. The apparent tension is resolved in Trinitarian theology: the Son is not an "other" to whom glory is given, but the one who is YHWH and shares the divine glory eternally.</p>',
    "9": '<p>"Behold, the former things have come to pass, and new things I now declare; before they spring forth I tell you of them." The divine foreknowledge that authenticates prophetic speech. Jesus\'s predictions of his death and resurrection — given before they occurred (Matt 16:21; 17:22-23; 20:18-19) — fulfill this claim: "I am telling you before it happens, so that when it does happen, you may believe that I am he" (John 13:19). Rev 1:19 commissions John to "write therefore the things that you have seen, those that are and those that are to take place after this" — the prophetic announcement of new things before they spring forth continues through the risen Christ.</p>',
    "10": '<p>"Sing to YHWH a new song, his praise from the end of the earth." Rev 5:9: "they sang a new song, saying, \'Worthy are you to take the scroll and to open its seals, for you were slain, and by your blood you ransomed people for God from every tribe and language and people and nation.\'" Rev 14:3: "they were singing a new song before the throne." The new song of Isaiah 42:10 is explicitly identified as the song of the Lamb in Revelation — the new thing that YHWH declared (v.9) generates a new worship that was impossible before the Servant accomplished his mission. Ps 98:1 also calls for "a new song" for the marvelous things YHWH has done — Christ\'s resurrection is the marvelous act that fulfills both Psalms and Servant Song.</p>',
    "11": '<p>"Let the desert and its cities lift up their voice, the villages that Kedar inhabits; let the habitants of Sela sing for joy, let them shout from the top of the mountains." The gathering of worship from the desert margins — Kedar (nomadic Arab tribes) and Sela (Petra/Edom) — is the beginning of the Gentile mission\'s reach. Acts 8:26-40: Philip baptizes the Ethiopian eunuch on the desert road to Gaza — the desert lifts its voice. The geographic universalism of the new song anticipates Paul\'s missionary arc from Jerusalem to Illyricum to Spain (Rom 15:19-24): the mountaintop shout reaches to the ends of the earth.</p>',
    "12": '<p>"Let them give glory to YHWH, and declare his praise in the coastlands." The coastlands that "wait for his Torah" (v.4) now give glory rather than merely waiting. The progression — from waiting (v.4) to worshipping (v.12) — is the trajectory of the Gentile mission in Acts: the people who sat in darkness (42:7) and waited for instruction (42:4) now respond with worship. Rev 15:4: "who will not fear, O Lord, and glorify your name? For you alone are holy. All nations will come and worship you." The coastlands\' final act is the worship that Christ\'s mission made possible.</p>',
    "13": '<p>"YHWH goes out like a mighty man; like a man of war he stirs up his zeal; he cries out, he shouts aloud, he shows himself mighty against his foes." The divine warrior who fights for his people. Rev 19:11-16: the rider on the white horse whose "eyes are like a flame of fire," wearing "a robe dipped in blood," who "wages war in righteousness" and strikes down the nations. John 2:17: "zeal for your house will consume me" — Jesus\'s temple-cleansing is the earthly enactment of the divine warrior\'s zeal. The Servant who was gentle with bruised reeds (v.3) is also the warrior who defeats the Serpent (3:15). Both gentleness and warfare belong to the Servant\'s full identity.</p>',
    "14": '<p>"For a long time I have held my peace; I have kept still and restrained myself; now I will cry out like a woman in labor; I will gasp and pant." The divine silence broken at last. Heb 1:1-2: "Long ago, at many times and in many ways, God spoke to our fathers by the prophets, but in these last days he has spoken to us by his Son." The incarnation is the end of the long divine restraint — the birth-cry of the new creation (the "woman in labor" <em>yôlēdâ</em>). John 1:14: "the Word became flesh" is the moment when the long-held peace ends and YHWH cries out in the person of his Son. The gasping and panting of the woman in labor becomes Gethsemane (Heb 5:7: "loud cries and tears") — the divine birth-cry voiced through the incarnate Son.</p>',
    "15": '<p>"I will lay waste mountains and hills, and dry up all their vegetation; I will turn the rivers into islands, and dry up the pools." The divine warrior\'s landscape-transformation as preparation for the march of the blinded people (v.16). The leveling of obstacles for the gospel\'s advance — Isa 40:4 (every mountain made low); Luke 3:5 (the Baptist\'s proclamation of leveling). The drying of waters and transformation of terrain is the new Exodus: as YHWH dried the Red Sea for Israel\'s deliverance, so the gospel\'s advance encounters YHWH\'s clearing of all obstacles that would prevent the blind from reaching him.</p>',
    "16": '<p>"And I will lead the blind in a way that they do not know, in paths that they have not known I will guide them. I will turn the darkness before them into light, the rough places into level ground. These are the things I do, and I do not forsake them." The divine guidance of the blind through unknown paths is the pastoral promise for the new community. John 10:3-4: "the sheep hear his voice, and he calls his own sheep by name and leads them out... he goes before them, and the sheep follow him, for they know his voice." 2 Cor 4:6: "God... has shone in our hearts to give the light of the knowledge of the glory of God in the face of Jesus Christ" — the turning of darkness to light before the blind (42:16) is the same act as the shining of divine light in Paul\'s heart on the Damascus road.</p>',
    "17": '<p>"They are turned back and utterly put to shame, who trust in carved idols, who say to metal images, \'You are our gods.\'" The shame of idolaters — those whose confidence is in things made by human hands. 1 Cor 8:4-6: "we know that \'an idol has no real existence\' and that \'there is no God but one\'... yet for us there is one God, the Father, from whom are all things... and one Lord, Jesus Christ." Acts 17:29-30: "we ought not to think that the divine being is like gold or silver or stone, an image formed by the art and imagination of man. The times of ignorance God overlooked, but now he commands all people everywhere to repent." Christ\'s resurrection is the demonstration that the living God who raised him is not the product of human art.</p>',
    "18": '<p>"Hear, you deaf, and look, you blind, that you may see!" The sudden address to the blind and deaf servant-people is the reversal of the healing commission (v.7: opening blind eyes) directed inward. Mark 8:18 (Jesus to the disciples): "Having eyes do you not see, and having ears do you not hear?" Rev 2:7,11,17,29: "He who has an ear, let him hear what the Spirit says to the churches" — the repeated call to spiritual hearing across the seven letters. The deaf who need to hear are not only the nations but also the community of faith that has become spiritually imperceptive. The Servant who opens blind eyes finds that his own people have closed theirs.</p>',
    "19": '<p>"Who is blind but my servant, or deaf as my messenger whom I send? Who is blind as my dedicated one, or blind as the servant of YHWH?" The shocking paradox: the servant who was commissioned to open blind eyes is himself blind. In the NT, this becomes the diagnosis of the religious establishment that rejected Christ. John 9:40-41: the Pharisees ask "are we also blind?" and Jesus answers, "if you were blind, you would have no guilt; but now that you say, \'We see,\' your guilt remains." Rom 11:7-8: "the elect obtained it, but the rest were hardened... \'God gave them a spirit of stupor, eyes that would not see and ears that would not hear.\'" The servant-nation called to witness is the first example of those who need the Servant\'s eye-opening.</p>',
    "20": '<p>"He sees many things, but does not observe them; his ears are open, but he does not hear." The progressive hardening — the ongoing exposure to revelation that produces no response. Rom 1:18-20: "what can be known about God is plain to them... for his invisible attributes, namely, his eternal power and divine nature, have been clearly perceived, ever since the creation of the world in the things that have been made. So they are without excuse." The "seeing many things" without perceiving is the state Paul diagnoses as the suppression of truth in unrighteousness. Heb 4:7 warns: "Today, if you hear his voice, do not harden your hearts" — the repeated opportunity to see and hear becomes the ground of greater accountability.</p>',
    "21": '<p>"YHWH was pleased, for his righteousness\' sake, to magnify his law and make it glorious." Matt 5:17-18: "Do not think that I have come to abolish the Law or the Prophets; I have not come to abolish them but to fulfill them. For truly, I say to you, until heaven and earth pass away, not an iota, not a dot, will pass from the Law until all is accomplished." The fulfillment of Torah by Christ is precisely the magnification and glorification of the law that Isaiah 42:21 anticipates. Rom 3:31: "Do we then overthrow the law by this faith? By no means! On the contrary, we uphold the law." The Sermon on the Mount is the enacted magnification of Torah — each "you have heard it said... but I say to you" deepens rather than annuls the law\'s demands.</p>',
    "22": '<p>"But this is a people plundered and looted; they are all of them trapped in holes and hidden in prisons; they have become plunder with none to rescue, spoil with none to say, \'Restore!\'" The captive, plundered people awaiting rescue is the condition that Christ\'s mission addresses. Luke 4:18: "to proclaim liberty to the captives... to set at liberty those who are oppressed." Rev 13:10: "If anyone is to be taken captive, to captivity he goes" — under the beast\'s rule the situation of 42:22 is reproduced; but the Lamb who was slain has purchased the captives (Rev 5:9: "by your blood you ransomed people for God"). The "none to rescue" of 42:22 is answered by the one who "gave his life as a ransom for many" (Matt 20:28).</p>',
    "23": '<p>"Who among you will give ear to this, will attend and listen for the time to come?" The prophetic call for attentive hearing of the judgment/salvation announcement. Matt 11:15: "He who has ears to hear, let him hear." Rev 2-3 (the seven churches): "He who has an ear, let him hear what the Spirit says to the churches" — the repeated call across the Apocalypse. The "time to come" (<em>lĕʿēt ʾāḥôr</em>, for the future) is the eschatological future that the Servant\'s mission inaugurates; those who hear now are positioned for what is coming. Heb 2:1: "we must pay much closer attention to what we have heard, lest we drift away from it."</p>',
    "24": '<p>"Who gave up Jacob to the looter, and Israel to the plunderers? Was it not YHWH, against whom we have sinned, in whose ways they would not walk, and whose law they would not obey?" The acknowledgment that YHWH himself gave his people up — the covenant judgment. Rom 1:24,26,28: "God gave them up to..." — Paul\'s three-fold use of the verb <em>paredōken</em> (handed over) in Romans 1 applies the same logic: the covenant God who hands over his sinful people to the consequences of their choices. The ultimate "giving over" is Christ: "he who did not spare his own Son but gave him up (<em>paredōken</em>) for us all" (Rom 8:32) — the Father gives the Son as the final answer to the handing-over that Israel\'s sin deserved.</p>',
    "25": '<p>"So he poured on him the heat of his anger and the might of battle; it set him on fire all around, but he did not understand; it burned him up, but he did not take it to heart." The repeated judgment that produces no comprehension — the fire of divine wrath that Israel endured without learning from it. Heb 12:5-11: "the Lord disciplines the one he loves" — discipline is meant to produce learning and righteousness. The failure of Israel in 42:25 (burning without understanding) is the cautionary context for the NT call to receive God\'s discipline fruitfully. In Christ, the fire fell on the one who did understand — who received the judgment he did not deserve so that those who deserved it might be spared. 2 Cor 5:21: "he made him to be sin who knew no sin."</p>',
  },
}

def main():
    existing = load_comm('mkt-christ', 'isaiah')
    merge_comm(existing, ISAIAH)
    save_comm('mkt-christ', 'isaiah', existing)
    # INTENT: Verify all 25 Isaiah 42 mkt-christ verses present against interlinear
    # CHANGE? If interlinear/isaiah.json ch 42 verse count changes, update expected total
    # VERIFY: Console shows complete with 25 verses; no MISSING output
    il = json.loads((ROOT / 'data' / 'interlinear' / 'isaiah.json').read_text())
    out = json.loads((ROOT / 'data' / 'commentary' / 'mkt-christ' / 'isaiah.json').read_text())
    missing = [v for v in il.get('42', {}) if v not in out.get('42', {})]
    if missing:
        print(f'  MISSING: {missing}')
    else:
        print(f'  OK: all Isaiah 42 mkt-christ verses present ({len(il.get("42", {}))} verses)')

if __name__ == '__main__':
    main()
